from collections import Counter, deque
class Solution:
    def longestSubsequenceRepeatedK(self, s, k):
        cnt = Counter(s)
        letters = sorted(c for c in cnt if cnt[c] >= k)
        def is_valid(sub):
            target = sub * k
            it = iter(s)
            return all(ch in it for ch in target)
        best = ''
        queue = deque(letters)
        while queue:
            cur = queue.popleft()
            if not is_valid(cur):
                continue
            if len(cur) > len(best) or (len(cur) == len(best) and cur > best):
                best = cur
            for c in letters:
                queue.append(cur + c)
        return best

