var longestSubsequenceRepeatedK = function(s, k) {
    const cnt = {};
    for (const c of s) cnt[c] = (cnt[c] || 0) + 1;
    const letters = Object.keys(cnt).filter(c => cnt[c] >= k).sort();
    function isValid(sub) {
        const target = sub.repeat(k);
        let idx = 0;
        for (let i = 0; i < s.length && idx < target.length; i++) {
            if (s[i] === target[idx]) idx++;
        }
        return idx === target.length;
    }
    let best = '';
    const queue = [...letters];
    while (queue.length) {
        const cur = queue.shift();
        if (!isValid(cur)) continue;
        if (cur.length > best.length || (cur.length === best.length && cur > best)) {
            best = cur;
        }
        for (const c of letters) queue.push(cur + c);
    }
    return best;
};
